def range_summary(nums):
    if not nums:
        return ''
    nums.sort()
    result = []
    i = start = 0
    while i < len(nums):
        if i + 1 < len(nums) and nums[i] + 1 == nums[i + 1]:
            i += 1
        else:
            if start != i:
                result.append(f'{nums[start]}-{nums[i]}')
            else:
                result.append(str(nums[i]))
            i += 1
            start = i
    return ','.join(result)
